SESSION_EXPIRY_HOURS = 1
TOKEN_LENGTH = 64  # bytes for session token


# --- Rate Limiting ---

def is_rate_limited(identifier, store, window, max_requests):
    """Check if an identifier is rate limited."""
    now = time.time()
    # Clean old entries
    store[identifier] = [t for t in store[identifier] if now - t < window]
    if len(store[identifier]) >= max_requests:
        return True
    store[identifier].append(now)
    return False


def rate_limit_by_ip(f):
    """Decorator to rate limit by IP address."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.remote_addr or '0.0.0.0'
        if is_rate_limited(client_ip, rate_limit_store, RATE_LIMIT_WINDOW, RATE_LIMIT_MAX_REQUESTS):
            return jsonify({'error': 'Too many requests. Please try again later.'}), 429
        return f(*args, **kwargs)
    return decorated_function


def is_account_locked(username):
    """Check if account is locked due to too many failed login attempts."""
    now = time.time()
    failed_login_store[username] = [
        t for t in failed_login_store[username] if now - t < FAILED_LOGIN_WINDOW
    ]
    return len(failed_login_store[username]) >= FAILED_LOGIN_MAX_ATTEMPTS


def record_failed_login(username):
    """Record a failed login attempt."""
    failed_login_store[username].append(time.time())


def clear_failed_logins(username):
    """Clear failed login attempts on successful login."""
    failed_login_store.pop(username, None)


# --- Password Hashing with bcrypt ---

def hash_password(password):
    """Hash a password using bcrypt with a random salt."""
    if isinstance(password, str):
        password = password.encode('utf-8')
    salt = bcrypt.gensalt(rounds=12)
    password_hash = bcrypt.hashpw(password, salt)
    return password_hash, salt


def verify_password(password, stored_hash):
    """Verify a password against a bcrypt hash."""
    if isinstance(password, str):
        password = password.encode('utf-8')
    if isinstance(stored_hash, str):
        stored_hash = stored_hash.encode('utf-8')
    try:
        return bcrypt.checkpw(password, stored_hash)
    except Exception:
        return False


# --- Session Token Management ---

def generate_session_token():
    """Generate a cryptographically secure session token."""
    return secrets.token_hex(TOKEN_LENGTH)


def create_session(username):
    """Create a new session for a user, invalidating any existing sessions."""
    # Invalidate existing sessions for this user
    tokens_to_remove = [
        token for token, data in sessions_db.items()
        if data['username'] == username
    ]
    for token in tokens_to_remove:
        del sessions_db[token]

    token = generate_session_token()
    now = datetime.utcnow()
    sessions_db[token] = {
        'username': username,
        'created_at': now,
        'expires_at': now + timedelta(hours=SESSION_EXPIRY_HOURS),
        'ip_address': request.remote_addr,
    }
    return token


def validate_session_token(token):
    """Validate a session token and return the associated username."""
    if not token or token not in sessions_db:
        return None

    session_data = sessions_db[token]
    now = datetime.utcnow()

    # Check expiration
    if now > session_data['expires_at']:
        del sessions_db[token]
        return None

    return session_data['username']


def invalidate_session(token):
    """Invalidate a session token."""
    sessions_db.pop(token, None)


def cleanup_expired_sessions():
    """Remove all expired sessions."""
    now = datetime.utcnow()
    expired = [
        token for token, data in sessions_db.items()
        if now > data['expires_at']
    ]
    for token in expired:
        del sessions_db[token]


# --- Authentication Decorator ---

def login_required(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = None

        # Check Authorization header
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]

        # Fall back to session cookie
        if not token:
            token = session.get('session_token')

        if not token:
            return jsonify({'error': 'Authentication required.'}), 401

        username = validate_session_token(token)
        if not username:
            return jsonify({'error': 'Authentication required.'}), 401

        g.current_user = username
        g.session_token = token
        return f(*args, **kwargs)
    return decorated_function


# --- Input Validation ---

def validate_credentials(data):
    """Validate that username and password meet basic requirements."""
    username = data.get('username', '').strip()
    password = data.get('password', '')

    errors = []
    if not username or len(username) < 3 or len(username) > 64:
        errors.append('Username must be between 3 and 64 characters.')
    if not password or len(password) < 8 or len(password) > 128:
        errors.append('Password must be between 8 and 128 characters.')

    # Basic character validation for username
    if username and not all(c.isalnum() or c in '_-.' for c in username):
        errors.append('Username may only contain alphanumeric characters, underscores, hyphens, and dots.')

    return username, password, errors


